const results = $input.first().json.results || [];

// ── Scoring ────────────────────────────────────────────────────
// Returns a relevance score for how "important in astronomy" an article is.
function scoreArticle(d) {
  const text = ((d.title || '') + ' ' + (d.summary || '')).toLowerCase();
  let score = 0;

  // HIGH-VALUE astronomy topics (score +3 each)
  const high = [
    /\bjwst\b|james webb|webb telescope|webb space telescope/,
    /\bhubble\b/,
    /asteroid|\bcomet\b|\bmeteor\b|near-earth|\bneo\b|apophis|potentially hazardous/,
    /\bmars\b.{0,30}(mission|rover|lander|probe)|perseverance|curiosity rover|ingenuity/,
    /artemis|lunar.*mission|moon.*mission|moon.*lander|lunar.*lander/,
    /\biss\b|space station|spacewalk|\beva\b|extravehicular/,
    /exoplanet|black hole|neutron star|\bpulsar\b|\bquasar\b|supernova|gamma.ray burst/,
    /nebula|\bgalaxy\b|dark matter|dark energy|gravitational wave/,
    /telescope.{0,20}discover|discover.{0,20}telescope|new astronomical|new discovery in space/,
    /rocket.*launch|launch.*rocket|liftoff|blastoff|successful.*launch|launch.*success/,
    /starship|falcon 9|new glenn|ariane 6|vulcan|electron rocket|new shepard.*flight/,
    /solar flare|aurora|cme|coronal mass|geomagnetic storm/,
    /james webb|\bjwst\b|spitzer|chandra x-ray|\bvla\b|very large array/,
  ];

  // MEDIUM-VALUE topics (score +1 each)
  const medium = [
    /spacecraft|\bprobe\b|orbiter|\blander\b|\bflyer\b/,
    /astronaut|cosmonaut|crew dragon|soyuz.*crew|crew.*soyuz/,
    /\bnasa\b|\besa\b|\bjax\b|\bisro\b|\broscosmos\b|\bcsa\b/,
    /satellite.*launch|launch.*satellite|smallsat|cubesat/,
    /solar system|\bsun\b|\bjupiter\b|\bsaturn\b|\bvenus\b|\bmercury\b|\buranus\b|\bneptune\b/,
    /space telescope|ground telescope|observatory/,
    /planetary science|astrophysics|cosmology|astrobiolog/,
    /reusable rocket|stage.*land|booster.*catch|reentry/,
  ];

  // NOISE — business/policy (score -2 each)
  const noise = [
    /\$[\d.]+\s*(billion|million)|valuation|funding round|series [a-f]\b|venture capital/,
    /contract awarded|contract for|acquisition|merger|\bipo\b|public offering/,
    /budget.*approp|approp.*budget|congressional|senate.*vote|house.*vote/,
    /\bceo\b|chief executive|appointed.*director|director.*appointed|executive.*hire/,
    /weather satellite|earth.*observation.*commercial|imagery.*subscription/,
    /insurance|lawsuit|patent|trademark/,
  ];

  for (const re of high)   if (re.test(text)) score += 3;
  for (const re of medium) if (re.test(text)) score += 1;
  for (const re of noise)  if (re.test(text)) score -= 2;

  return score;
}

// ── Categorisation ─────────────────────────────────────────────
function getCategory(d) {
  const text = ((d.title || '') + ' ' + (d.summary || '')).toLowerCase();
  if (/picture of the day|\bapod\b|image of the day|astronomy picture/.test(text)) return 'APOD';
  if (/asteroid|\bcomet\b|\bmeteor\b|near-earth|\bneo\b|apophis|potentially hazardous/.test(text)) return 'Asteroid';
  if (/\biss\b|international space station|spacewalk|\beva\b|extravehicular/.test(text)) return 'ISS';
  if (/launch|rocket|liftoff|blastoff|starship|falcon|ariane|soyuz|new glenn|vulcan|electron/.test(text)) return 'Launch';
  return 'General';
}

// ── Filter ─────────────────────────────────────────────────────
// Keep only articles that score >= 2 (at least one medium + one more, or one high topic)
const now = new Date().toISOString();

const kept = results
  .map(d => ({ d, score: scoreArticle(d) }))
  .filter(({ score }) => score >= 2)
  .sort((a, b) => b.score - a.score);

if (kept.length === 0) {
  throw new Error('No articles passed the relevance filter. The API may have returned only business/policy news.');
}

return kept.map(({ d }) => ({
  json: {
    timestamp:      now,
    type:           'archive',
    source:         d.news_site    || '',
    title:          d.title        || '',
    aiSummary:      d.summary      || '',
    tweet:          '',
    localNote:      '',
    category:       getCategory(d),
    localRelevance: '',
    url:            d.url          || '',
    imageUrl:       d.image_url    || '',
    publishedAt:    d.published_at || '',
  }
}));
